include <cstdint>   
#include <chrono>   
//returns elapsed time in nanoseconds   
uint64_t timeWithChrono() { using namespace std::chrono; uint64_t start $=$ duration_cast<nanoseconds>(steady_clock::now().time_since_epoch().count(); //run something uint64_t end $=$ duration_cast<nanoseconds>(steady_clock::now().time_since_epoch().count(); uint64_t delta $\equiv$ end - start; return delta;   
}

include <x86intrin.h>   
#include <cstdint>   
